# NL ARD.  Amsterdam Singelgracht - Rotterdam Centraal
#
let ar = path("d3.nl.ard");

with detail = 4, railway = :first :double :cat:dc15 :pax {
    # point.nl.Singelgracht  nl.DHA

    # point.nl.Overbrakerpolder  nl.ZSG

    with link = "line.nl.ARD" {
        track(:ror, ar[:obr + 2dl, :asl - 619m] << 2.25mo);
    }

    # point.nl.Amsterdam-Sloterdijk  nl.ZSG

    with link = "line.nl.ARD" {
        track(:ror,
                ar[:asl + 199m, :asl + 200m] << 3mo
            ..  ar[:asl.yr, :asl.xz] << 4.25mo
        );
        track(
                ar[:asl.xz - 0.1dl, :asl.xz] << 4.25mo
            ..  ar[:asl.zz, :asl.zz + 0.1dl]
        );
    }
}

with detail = 4, railway = :first :double :pax :removed {
    let awi = path("d3.nl.ard.awi");

    with link = "point.nl.Amsterdam-Willemspoort", railway = :station {
        track(awi[:awi, :awi + 0.5sw]);
    }

    with link = "line.nl.ARD" {
        track(awi[:awi + 500m, :asl.zz]);
    }
}

with detail = 4, railway = :first :double :cat:dc15 :pax {
    with link = "line.nl.ARD" {
        track(ar[:asl.zz, :asl.zz + 1.21km]);
        line_label(:left:n, ar[:asl.zz + 1.2km] << 0.5mo << 0.5mt, "ARD");
