    }

    with link = "line.nl.ARD" {
        track(ar[:hal + 0.49sw, :hsp - 0.49sw]);
    }

    with link = "point.nl.Haarlem-Spaarnwoude", railway = :station {
        track(ar[:hsp - 0.5sw, :hsp + 0.5sw]);
