            "Haarlem Spaarnwoude", "ARD: 14,290"
        );
    }

    with link = "line.nl.ARD" {
        track(ar[:hsp + 0.49sw, :spb + 0.1dl]);
    }

    with link = "point.nl.Spaarnebrug-Haarlem", railway = :station {
        marker(:left :de.dkst, ar[:spb] << 0.5mo << 0.5mt);
        station(:left, ar[:spb] << 0.5mo << 0.5mt << 1sh + (-1.5dt, 1dt),
            vbox(:center:topbase :small, "Spaarnebrug", "bij Haarlem"),
            "ARD: 16,266"
        );
    }

    with link = "point.nl.Haarlem", railway = :station :single {
        # NL ARD goederen
        track(:nopax,
                ar[:haa - 400m - 1.1dl, :haa - 400m - 1dl] << 0.5mo
            --  ar[:haa - 400m, :hzu.yn + 0.1dl] << 1.5mo
        );

        # NL ARD up
        track(ar[:spb - 0.1dl, :hzu.yn + 0.1dl] << 0.5mo);

        # NL ARD dn
        track(ar[:spb - 0.1dl, :hzu.yn + 0.1dl] >> 0.5mo);

        # NL HZV up
        track(
                ar[:haa.yu + 0.9dl, :haa.yu + 1dl] >> 0.5mo
            --  ar[:haa.yu + 2dl, :haa.yu + 3dl] >> 1.5mo
        );

        track(:side :nopax,
                ar[:haa - 320m, :haa.yu - 2.5dl] >> 1.5mo
            --  ar[:haa.yu - 1.5dl, :haa.yu - 1.4dl] >> 2.5mo
        );

        # NL HZV dn
        track(
                ar[:haa - 501m, :haa - 500m] >> 0.5mo
            --  ar[:haa - 500m + 1dl, :haa - 320m] >> 1.5mo
            --  ar[:haa - 320m + 1dl, :haa.yu + 3dl] >> 2.5mo
        );
            track(:side,
                    ar[:haa.yu - 5dl] >> 2.5mo
                --  ar[:haa.yu - 3dl] >> 0.5mo
            );

        # NL HUG up
        track(
                ar[:haa.yu - 0.6dl, :haa.yu - 0.5dl] >> 0.5mo
            --  ar[:haa.yu + 2.5dl, :haa.yu + 3dl] >> 3.5mo
        );

        # NL HUG dn
        track(
                ar[:haa.yu - 2.1dl, :haa.yu - 2dl] >> 0.5mo
            --  ar[:haa.yu + 2dl, :haa.yu + 3dl] >> 4.5mo
        );

        marker(:left :de.bf, ar[:haa] << 1.5mo << 0.5mt);
         station(:top, ar[:haa] >> 2.5mo >> 0.5mt + (1dt, -1.5dt),
             span(:bold, "Haarlem"),
             hbox(:center:top,
                vbox(:right:top,
                    "[HUG: ", "[HZV: ", "ARD: ", span(:removed, "AHM: ")
                ),
                vbox(:sep:top,
                    hbox(:sep:base, "−0,", anchor(), "012]"),
                    hbox(:sep:base, "0,", anchor(), "059]"),
                    hbox(:sep:base, "16,", anchor(), "882"),
                    hbox(:sep:base :removed, "18,", anchor(), "0")
                )
            )
         );
    }

    with link = "point.nl.Zuidelijke-splitsing-Haarlem",
         railway = :station :single
    {
        # NL ARD goederen
        track(:nopax, ar[:hzu.yn, :zij + 0.5sw] << 1.5mo);

        # NL ARD up
        track(ar[:hzu.yn, :zij + 0.5sw] << 0.5mo);

        # NL ARD dn
        track(ar[:hzu.yn, :zij + 0.5sw] >> 0.5mo);

        # NL HZN
        track(:nopax,
                ar[:hzu.yn, :hzu - 1dl] >> 1.5mo
            --  ar[:hzu + 2dl, :hzu + 2.1dl] << 1.5mo
